#include <bits/stdc++.h>
using namespace std;

int n, a[100005];
vector<int> l[100005];
int f[100005];

int DFS(int x) {
    if (f[x]) return f[x];
    int ans = 0;
    for (int y : l[x]) {
        if (a[y] < a[x]) {
            ans += DFS(y);
        }
    }
    f[x] = ans + 1;
    return ans + 1;
}

int main() {
    cin >> n;
    for (int i = 1; i <= n; i++) {
        cin >> a[i];
    }
    for (int i = 0; i < n - 1; i++) {
        int u, v;
        cin >> u >> v;
        l[u].push_back(v);
        l[v].push_back(u);
    }
    int ans = 0;
    for (int i = 1; i <= n; i++) {
        ans = max(ans, DFS(i));
    }
    cout << ans;
    return 0;
}
